def is_palindrome(string: str) -> bool:
    """ Test if given string is a palindrome """
    return string == string[::-1]


def make_palindrome(string: str) -> str:
    """ Find the shortest palindrome that begins with a supplied string.
    Algorithm idea is simple:
    - Find the longest postfix of supplied string that is a palindrome.
    - Append to the end of the string reverse of a string prefix that comes before the palindromic suffix.
    >>> make_palindrome('')
    ''
    >>> make_palindrome('cat')
    'catac'
    >>> make_palindrome('cata')
    'catac'
    """
    palindrome = []
    is_even = len(string) % 2 == 0
    palindrome_length = len(string) // 2

    # If supplied string is a palindrome
    if is_palindrome(string):
        return string

    # If supplied string is not a palindrome
    else:
        # If supplied string is even
        if is_even:
            # If supplied string is shorter than 3
            if palindrome_length < 3:
                palindrome = string
            # If supplied string is longer than 3
            else:
                # If supplied string is shorter than 5
                if palindrome_length < 5:
                    palindrome = string[-1:] + string[-2::-1]
                # If supplied string is longer than 5
                else:
                    palindrome = string[-1:] + string[-2:] + string[-3::-1]
        # If supplied string is odd
        else:
            # If supplied string is shorter than 2
            if palindrome_length < 2:
                palindrome = string
            # If supplied string is longer than 2
            else:
                # If supplied string is shorter than 4
                if palindrome_length < 4:
                    palindrome = string[-1:] + string[-2::-1]
                # If supplied string is longer than 4
                else:
                    palindrome = string[-1:] + string[-2:] + string[-3::-1]

    return ''.join(palindrome)

def flip_case(string: str) -> str:
    """ For a given string, flip lowercase characters to uppercase and uppercase to lowercase.
    >>> flip_case('Hello')
    'hELLO'
    """
    result = []
    for c in string:
        if c.islower():
            result.append(c.upper())
        else:
            result.append(c.lower())
    return ''.join(result)
